#include <iostream>
#include <vector>
#include <string>
#include <numeric>

// Advanced enterprise simulation showing: std::reverse, min_element, max_element
class DiagnosticProcessor {
private:
    std::vector<double> telemetryLogs;

public:
    void logValue(double val) {
        telemetryLogs.push_back(val);
    }

    double calculateMetrics() const {
        if (telemetryLogs.empty()) return 0.0;
        double sum = std::accumulate(telemetryLogs.begin(), telemetryLogs.end(), 0.0);
        return sum / telemetryLogs.size();
    }
};

int main() {
    DiagnosticProcessor processor;
    processor.logValue(98.4);
    processor.logValue(101.2);
    processor.logValue(99.8);

    std::cout << "Diagnostic Processor active.\n";
    std::cout << "Average Telemetry Metric: " << processor.calculateMetrics() << "\n";
    return 0;
}

